3_real_world_example.code:
const arr = [1, 2, 3];

// 1. Ask arr for 'push'. It doesn't own it. 
// 2. Checks Prototype (Array.prototype). Found it!
arr.push(4);

// 1. Ask arr for 'hasOwnProperty'. It doesn't own it.
// 2. Checks Prototype (Array.prototype). Not there either.
// 3. Checks Prototype's Prototype (Object.prototype). Found it!
console.log(arr.hasOwnProperty('length')); // true

6_edge_case.code:
const parent = { greet: () => 'Hi from parent' };
const child = Object.create(parent);
child.greet = () => 'Hi from child'; // Shadows parent's greet

console.log(child.greet()); // 'Hi from child'
